// Get today's questions for a given HD type and language
// Uses date-based seed to ensure no repeat of same combination two days in a row
export function getDailyCheckinQuestions(hdType, language = 'en') {
  const lang = CHECKIN_QUESTIONS[language] || CHECKIN_QUESTIONS['en']
  const typeQuestions = lang[hdType] || lang['Generator']

  // Date-based index: changes daily, no repeats day-to-day
  const today = new Date()
  const dayOfYear = Math.floor((today - new Date(today.getFullYear(), 0, 0)) / 86400000)
  const seed = today.getFullYear() * 1000 + dayOfYear

  const mirrorIdx = seed % typeQuestions.mirroring.length
  const gratIdx = (seed + 3) % typeQuestions.gratitude.length  // offset to decorrelate
  const intentIdx = (seed + 7) % typeQuestions.intention.length

  return [
    { id: 'mirroring', category: 'mirroring', question: typeQuestions.mirroring[mirrorIdx] },
    { id: 'gratitude', category: 'gratitude', question: typeQuestions.gratitude[gratIdx] },
    { id: 'intention', category: 'intention', question: typeQuestions.intention[intentIdx] },
  ]
}

export default CHECKIN_QUESTIONS